{
  "verses": [
    {
      "n": 6,
      "column": "left",
      "text": "Un Dahwids dallija tohs\nRahrtäg/ ar Wahrdu tohs Behr-\nnus Lewja/ Gersona/ Kaâta un\nMerara.\n"
    },
    {
      "n": 7,
      "column": "left",
      "text": "No teem Gersonitexeem bi-\nja/ Laëdans un Simejus.\n"
    },
    {
      "n": 8,
      "column": "left",
      "text": "Laëdana Behrni bija: Je-\nels tas Wirfneeks un Setans/\nun Jeëls tee trihs.\n"
    },
    {
      "n": 9,
      "column": "left",
      "text": "Simeja Behrni bija: Sa-\nlomits/ un Asiëls/ un Arans tee\ntrihs/ tchee bija tee Wirfneeki to\nTehwu Namma no Laëdana.\n"
    },
    {
      "n": 10,
      "column": "left",
      "text": "Un Simeja Behrni bija:\nJakats/ Sinus un Jeüg/ un\nBrijug/ tchee tschetri bija Sime-\nja Behrni.\n"
    },
    {
      "n": 11,
      "column": "left",
      "text": "Un Jakats bija tas pir-\nmajs/ un Sinus tas ohtrs. Bet\nJeügam un Brijam ne bij dauds\nBehrnu/ tapehz tappe tee par\nweenu Tehwa Naïnn lihdsinati.\n"
    },
    {
      "n": 12,
      "column": "left",
      "text": "Un Kaâta Behrni bija:\nAmrains/ Jezears/ Eebrons un\nUsiels/ tee tschetri.\n"
    },
    {
      "n": 13,
      "column": "left",
      "text": "Amrains Behrni bija:\nAäröns un Mohsus. Un Aä-\nrons tappe atschkirts/ ka tas ki/ kas pehz to Wahrdo Pu-\ntahs wifs fwehtakas Leetas fiveh-\ntitu lihds ar faweem Dehleemi\nmuhſchigt/ preekich ta KUNGA\nWaigu kwehpinaht/ un winnam\ntaspoht/ un eekich Winna Wahr-\nDa muhſchigi fwchtih.\n"
    },
    {
      "n": 14,
      "column": "left",
      "text": "Un Mohsus ta Deewa\n"
    },
    {
      "n": 15,
      "column": "right",
      "text": "Mohsus Behrni bija: G\nsons un Eliësers.\n"
    },
    {
      "n": 16,
      "column": "right",
      "text": "Gersona Behrni bi\nSebuels tas Wirfneeks.\n"
    },
    {
      "n": 17,
      "column": "right",
      "text": "Un Eliësera Behrni bi\nRekabijus tas Wirfneeks.\nEliëseram ne bij zittu Behru\nBet Rekabijus Behrni wa-\njahs dauds wairak.\n"
    },
    {
      "n": 18,
      "column": "right",
      "text": "Jezearks Behrni bija\nWirfneeks Salomits.\n"
    },
    {
      "n": 19,
      "column": "right",
      "text": "Eebroña Behrni bi\nJerijus tas pirmajs/ Amarij\ntas ohtrs/ Jeasiëls tas treffha\nun Jakineams tas zettortajs.\n"
    },
    {
      "n": 20,
      "column": "right",
      "text": "Ustëka Behrni bija: M\nkus tas pirmajs/ un Jesijus t\nohtrs.\n"
    },
    {
      "n": 21,
      "column": "right",
      "text": "Merara Behrni bi\nMaëlus un Musus. Ma-\nBehrni bija/ Eeleasars un Rie\n"
    },
    {
      "n": 23,
      "column": "right",
      "text": "Un Eeleasars nomiru\nun tam Dehlu ne bija bet M\ntas ween/ un Kifa Behrni w\nnu Brahti apxeheine tahs.\n"
    },
    {
      "n": 23,
      "column": "right",
      "text": "Musa Behrni bija/ M\nelus/ Eders un Jeremots/tee tri\n"
    },
    {
      "n": 24,
      "column": "right",
      "text": "Schee bija Lewja Beh-\npehz sawu Tehwo Namme\nfawo Tehwo Namnu Wirfn-\ntappe lihdsinati/ pehz winnu G\nwahn/ darridami tahs Kal-\nchanas Darbu ta KUNGA\nNaminâ/ diwidesmits Gadd\nun wairak wezzi.\n"
    },
    {
      "n": 25,
      "column": "right",
      "text": "Jo Dahwids bij fazzij\nTas KUNGS Israëta Dee\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
